import random
import time

class Lift:
    def __init__(self, id):
        self.id = id
        self.current_floor = 1
        self.direction = 0  # 1 for up, -1 for down, 0 for idle

    def move(self):
        if self.direction == 1:
            self.current_floor += 1
        elif self.direction == -1:
            self.current_floor -= 1

    def __str__(self):
        return f'Lift {self.id} is at floor {self.current_floor}'

class Building:
    def __init__(self, num_lifts, num_floors):
        self.num_lifts = num_lifts
        self.num_floors = num_floors
        self.lifts = [Lift(i) for i in range(1, num_lifts + 1)]

    def simulate(self, crowd_size, hours):
        for hour in range(hours):
            print(f'Hour {hour+1}:')
            for lift in self.lifts:
                print(lift)
            for _ in range(crowd_size):
                lift = random.choice(self.lifts)
                if random.random() < 0.7:  # 70% chance of going up
                    lift.direction = 1
                else:
                    lift.direction = -1
                lift.move()
                if lift.current_floor > self.num_floors:
                    lift.current_floor = self.num_floors
                    lift.direction = -1
                elif lift.current_floor < 1:
                    lift.current_floor = 1
                    lift.direction = 1
            print()
            time.sleep(0.5)

    def morning_rush(self, crowd_size):
        for _ in range(crowd_size):
            lift = random.choice(self.lifts)
            lift.direction = 1
            lift.move()

    def evening_rush(self, crowd_size):
        for _ in range(crowd_size):
            lift = random.choice(self.lifts)
            lift.direction = -1
            lift.move()

