import random
import time
import matplotlib.pyplot as plt

class Lift:
    def __init__(self, id, num_floors):
        self.id = id
        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 1
        self.passengers = 0
        self.usage_count = 0

    def move(self):
        if self.passengers > 0:
            if self.direction == 1 and self.current_floor < self.num_floors:
                self.current_floor += 1
            elif self.direction == -1 and self.current_floor > 1:
                self.current_floor -= 1
            else:
                self.direction *= -1
            self.usage_count += 1
        else:
            self.passengers = random.randint(0, 10)
            self.direction = 1 if self.current_floor < self.num_floors // 2 else -1

    def add_passenger(self):
        if self.passengers < 10:
            self.passengers += 1
            return True
        return False

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i, num_floors) for i in range(num_lifts)]

    def simulate(self, crowd_size, hours):
        usage_counts = [[0 for _ in range(hours)] for _ in range(self.num_lifts)]
        for hour in range(hours):
            for lift in self.lifts:
                lift.move()
                if random.random() < crowd_size / 100:
                    lift.add_passenger()
                usage_counts[lift.id][hour] = lift.usage_count
        return usage_counts

    def plot_usage(self, usage_counts):
        for i, counts in enumerate(usage_counts):
            plt.plot(counts, label=f'Lift {i+1}')
        plt.xlabel('Hour')
        plt.ylabel('Usage Count')
        plt.title('Lift Usage Over Time')
        plt.legend()
        plt.show()

