import random
import time

class Lift:
    def __init__(self, name, num_floors):
        self.name = name
        self.num_floors = num_floors
        self.current_floor = 1
        self.queue = []

    def move_to_floor(self, floor):
        if floor != self.current_floor:
            print(f"Lift {self.name} moving from floor {self.current_floor} to floor {floor}")
            self.current_floor = floor

    def add_to_queue(self, floor):
        self.queue.append(floor)

    def process_queue(self):
        if self.queue:
            next_floor = self.queue.pop(0)
            self.move_to_floor(next_floor)
            print(f"Lift {self.name} arrived at floor {next_floor}")
        else:
            print(f"Lift {self.name} is idle")

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i+1, num_floors) for i in range(num_lifts)]

    def simulate(self, crowd_size, hours):
        for hour in range(hours):
            print(f"\nHour {hour+1}:")
            for _ in range(crowd_size):
                lift = random.choice(self.lifts)
                floor = random.randint(1, self.num_floors)
                lift.add_to_queue(floor)
            for lift in self.lifts:
                lift.process_queue()
            time.sleep(1)

