import random
import time
import threading

class Lift:
    def __init__(self, id, num_floors):
        self.id = id
        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 1
        self.passengers = 0
        self.lock = threading.Lock()

    def move(self):
        with self.lock:
            if self.direction == 1:
                if self.current_floor < self.num_floors:
                    self.current_floor += 1
                else:
                    self.direction = -1
            else:
                if self.current_floor > 1:
                    self.current_floor -= 1
                else:
                    self.direction = 1

    def pick_up(self, num_passengers):
        with self.lock:
            self.passengers += num_passengers

    def drop_off(self, num_passengers):
        with self.lock:
            self.passengers -= num_passengers
            if self.passengers < 0:
                self.passengers = 0

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i, num_floors) for i in range(num_lifts)]
        self.crowd_size = 0

    def simulate(self, crowd_size, hours):
        self.crowd_size = crowd_size
        threads = []
        for lift in self.lifts:
            thread = threading.Thread(target=self.run_lift, args=(lift, hours))
            threads.append(thread)
            thread.start()
        for thread in threads:
            thread.join()

    def run_lift(self, lift, hours):
        for hour in range(hours):
            if hour < 8 or hour > 17:
                num_passengers = random.randint(0, self.crowd_size // 10)
            elif hour < 9 or hour > 16:
                num_passengers = random.randint(0, self.crowd_size // 5)
            else:
                num_passengers = random.randint(0, self.crowd_size // 20)
            lift.pick_up(num_passengers)
            lift.move()
            lift.drop_off(num_passengers // 2)
            print(f"Lift {lift.id} is at floor {lift.current_floor} with {lift.passengers} passengers")
            time.sleep(1)

