        for lift in self.lifts:
            if random.random() < 0.5:
                lift.direction = 1
                lift.pick_up(num_passengers)
            else:
                lift.direction = -1
                lift.drop_off(num_passengers)

        for lift in self.lifts:
            lift.move()

        return [lift.passengers for lift in self.lifts]

