class Elevator:
    def __init__(self, id):
        self.id = id
        self.current_floor = 1
        self.direction = 1
        self.busy = False

    def step(self, building, hour):
        if not self.busy:
            if random.random() < self.get_probability(hour):
                self.busy = True
                destination_floor = random.randint(1, building.num_floors)
                self.direction = np.sign(destination_floor - self.current_floor)
                self.current_floor += self.direction
                if self.current_floor == destination_floor:
                    self.busy = False
        else:
            self.current_floor += self.direction
            if self.current_floor == destination_floor:
                self.busy = False

    def get_probability(self, hour):
        if hour < 8 or hour > 17:
            return 0.1
        elif hour < 12:
            return 0.5
        elif hour < 14:
            return 0.2
        else:
            return 0.3

