        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 1

    def move(self):
        hour = int(time.strftime("%H"))
        if hour >= 7 and hour < 9:  # morning rush hour
            self.speed = 2
        elif hour >= 12 and hour < 14:  # lunch break
            self.speed = 1.5
        elif hour >= 16 and hour < 18:  # evening rush hour
            self.speed = 2
        else:
