            self.direction = 1
        elif self.current_floor == self.num_floors and self.direction == 1:
            self.direction = -1

        self.current_floor += self.direction * self.speed
        if self.current_floor < 1:
            self.current_floor = 1
        elif self.current_floor > self.num_floors:
            self.current_floor = self.num_floors

        print(f"Elevator {self.id} is at floor {int(self.current_floor)}")

